import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { Subheader, SimpleListBoard, ContactUsForm } from '../../includes';
import { Grid } from '@material-ui/core';
import { insureUtil, insureUtilStrings } from '../utils';
import { KnowledgeArea } from '../Home/KnowledeArea';
import { insureAboutUsActions } from '../AboutUs';


const style = theme => ({
    root: {
        backgroundColor : insureUtil.getTheme().gainboro,
    },
    container : {
        margin : "100px 20px",
    },
    header : {
        color : insureUtil.getTheme().secondary,
    },
    send : {
        backgroundColor : insureUtil.getTheme().primary,
        color : insureUtil.getTheme().white,
        "&:hover" : {
            backgroundColor : insureUtil.getTheme().primary,
        }
    },
    contactInfo : {
        [theme.breakpoints.down("xs")] : {
            marginBottom : 50
        }
    }
})
class _ContactUs extends Component {
    componentDidMount() {
        
    }
    
    onSendClick(name, email, message, callback){
        const {dispatch} = this.props;
        insureAboutUsActions.addMessage(
            {name, email, message}, 
            done=>callback(done)
        )(dispatch);
    }
    nameMapper(name){
        switch(name){
            case "address" : return "Address";
            case "phone" : return "Phone";
            case "email" : return "Email";
            default : return name;
        }
    }
    render() {
        const {
            classes,
            [insureUtilStrings.settings] : settings,
            [insureUtilStrings.subheadImage] : subheadImage
        } = this.props;
        let contactItem;
        if(settings){
            const {item} = settings.getFirstObjectByPropValue("name", "contactInfo") || {};
            contactItem = item;
        }
        return (
            <div className={classes.root}>
                <Subheader
                    title="Contact Us"
                    image_url={subheadImage}
                    />
                <div className={classes.container}>
                    <Grid container spacing={2}>
                        <Grid className={classes.contactInfo} style={{padding : 10}} item xs={12} sm={6} md={6} lg={6} xl={6}>
                            <SimpleListBoard
                                classes={{
                                    header : classes.header
                                }}
                                title="CONTACT US"
                                skip={["facebook", "instagram", "twitter"]}
                                data={contactItem ? contactItem.value : {}}
                                nameMapper={this.nameMapper.bind(this)}
                                valueMapper={(name, value)=>value}/>
                                
                        </Grid>
                        <Grid item xs={12} sm={6} md={6} lg={6} xl={6}>
                            <ContactUsForm
                                onSendClick={this.onSendClick.bind(this)}
                                classes={{
                                    send : classes.send
                                }}/>
                        </Grid>
                    </Grid>
                </div>
                <KnowledgeArea/>
            </div>
        );
    }
}


_ContactUs.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({insureUtilReducer}) => ({
    [insureUtilStrings.settings] : insureUtilReducer[insureUtilStrings.settings],
    [insureUtilStrings.subheadImage] : insureUtilReducer[insureUtilStrings.subheadImage],
})


export const ContactUs = connect(mapStateToProps)(withStyles(style)(_ContactUs));
export {ContactUs as default}